1	export type Item = {
2	  type: string;
3	  cursed?: boolean;
4	};
5	
6	export type QuoteStep = { op: "quote"; items: Item[] };
7	
8	export type Step = QuoteStep;
9	
10	export type Scenario = {
11	  customer: { yearsWithMHPCO: number };
12	  steps: Step[];
13	};
14	
15	export type QuoteResult = { premium: number };
16	
17	export type ScenarioResult = {
18	  results: QuoteResult[];
19	};
20	
21	const PROCESSING_FEE = 5;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	const BLOCK_SIZE = 3;
33	const BLOCK_PRICE = 60;
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;
37	
38	const countsByType = (items: Item[]): Map<string, number> =>
39	  items.reduce(
40	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
41	    new Map<string, number>()
42	  );
43	
44	const groupTotal = (type: string, count: number): number =>
45	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
46	    ? BLOCK_PRICE
47	    : count * unitPrice(type);
48	
49	const sumBasePremiums = (items: Item[]): number => {
50	  let total = 0;
51	  for (const [type, count] of countsByType(items)) {
52	    total += groupTotal(type, count);
53	  }
54	  return total;
55	};
56	
57	const itemSurcharges = (item: Item): number => {
58	  let surcharge = 0;
59	  if (item.cursed) surcharge += unitPrice(item.type) * 0.5;
60	  return surcharge;
61	};
62	
63	const sumItemSurcharges = (items: Item[]): number =>
64	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
65	
66	const quote = ({ items }: QuoteStep): QuoteResult => ({
67	  premium: sumBasePremiums(items) + sumItemSurcharges(items) + PROCESSING_FEE,
68	});
69	
70	export const runScenario = (scenario: Scenario): ScenarioResult => ({
71	  results: scenario.steps.map(quote),
72	});
